def construct():
    """
    Hybrid approach combining:
    - Non-uniform vertex roles: designated hub vertices with asymmetric targeting
    - Bimodal out-degree distribution to absorb N++ burden
    - Deliberate structural asymmetry to break algebraic plateaus
    - Sophisticated plateau traversal accepting neutral moves
    - Coordinated multi-flip sequences for escape
    """
    np.random.seed(42)
    N = 47
    A = np.zeros((N, N), dtype=np.int8)

    # Strategy 1: Bimodal degree structure
    # ~15 "hub" vertices with high out-degree (~16)
    # ~32 "regular" vertices with lower out-degree (~10)
    num_hubs = 15
    hubs = set(range(num_hubs))
    regulars = set(range(num_hubs, N))

    # Build asymmetric base: hubs point densely, regulars point sparsely
    # Create unbalanced layers to guide structure
    layer_size_1 = 16
    layer_size_2 = 16
    layer_size_3 = 15

    layer_1 = set(range(layer_size_1))
    layer_2 = set(range(layer_size_1, layer_size_1 + layer_size_2))
    layer_3 = set(range(layer_size_1 + layer_size_2, N))

    # Hubs distributed across layers
    hubs_per_layer = [5, 5, 5]
    hub_assignment = {}
    hub_idx = 0
    for layer_idx, layer in enumerate([layer_1, layer_2, layer_3]):
        for _ in range(hubs_per_layer[layer_idx]):
            if hub_idx < num_hubs:
                hub_assignment[hub_idx] = layer_idx
                hub_idx += 1

    # Dense bipartite between consecutive layers (cyclic)
    for u in layer_1:
        for v in layer_2:
            if u not in hubs or v not in hubs:
                A[u, v] = 1

    for u in layer_2:
        for v in layer_3:
            if u not in hubs or v not in hubs:
                A[u, v] = 1

    for u in layer_3:
        for v in layer_1:
            if u not in hubs or v not in hubs:
                A[u, v] = 1

    # Hubs: selective high-degree targeting
    # Each hub points to ~14-16 carefully chosen vertices across layers
    np.random.seed(43)
    for hub in hubs:
        current_deg = int(A[hub].sum())
        hub_layer = hub_assignment.get(hub, 0)

        # Target vertices from non-adjacent layers preferentially
        target_layers = [(hub_layer + 1) % 3, (hub_layer + 2) % 3]
        candidates = []
        for layer_idx in target_layers:
            if layer_idx == 0:
                candidates.extend([v for v in layer_1 if v != hub and not A[hub, v] and not A[v, hub]])
            elif layer_idx == 1:
                candidates.extend([v for v in layer_2 if v != hub and not A[hub, v] and not A[v, hub]])
            else:
                candidates.extend([v for v in layer_3 if v != hub and not A[hub, v] and not A[v, hub]])

        target_count = min(16 - current_deg, len(candidates))
        for v in candidates[:target_count]:
            A[hub, v] = 1
            current_deg += 1

    # Ensure minimum out-degree 8 for all vertices
    for i in range(N):
        out_deg = int(A[i].sum())
        if out_deg < 8:
            candidates = [j for j in range(N) if j != i and not A[i, j] and not A[j, i]]
            need = 8 - out_deg
            for j in candidates[:need]:
                A[i, j] = 1

    # Helper functions
    def score_vertex(v):
        """Return max(0, |N++(v)| - |N+(v)| + 1)"""
        out_neighbors = set(np.where(A[v] == 1)[0])
        if not out_neighbors:
            return 0
        dist2 = set()
        for u in out_neighbors:
            dist2.update(np.where(A[u] == 1)[0])
        dist2.discard(v)
        dist2 -= out_neighbors
        return max(0, len(dist2) - len(out_neighbors) + 1)

    def total_excess():
        return sum(score_vertex(v) for v in range(N))

    def is_strongly_connected():
        """BFS forward and backward from vertex 0"""
        visited_fwd = set([0])
        stack = [0]
        while stack:
            u = stack.pop()
            for v in np.where(A[u] == 1)[0]:
                if v not in visited_fwd:
                    visited_fwd.add(v)
                    stack.append(v)

        if len(visited_fwd) < N:
            return False

        visited_bwd = set([0])
        stack = [0]
        while stack:
            v = stack.pop()
            for u in np.where(A[:, v] == 1)[0]:
                if u not in visited_bwd:
                    visited_bwd.add(u)
                    stack.append(u)

        return len(visited_bwd) == N

    # Local search with aggressive plateau traversal
    max_iter = 4000
    iteration = 0
    best_excess = total_excess()
    plateau_counter = 0
    max_plateau = 300

    while iteration < max_iter and plateau_counter < max_plateau:
        improved = False

        # Try random flips and coordinated multi-flips
        for attempt in range(min(200, max_iter - iteration)):
            # Generate flip candidates
            flip_sequence = []

            # Primary flip
            i, j = np.random.choice(N, 2, replace=False)
            if A[i, j] == 0 and A[j, i] == 0:
                flip_sequence.append((i, j, 1))
            elif A[i, j] == 1:
                flip_sequence.append((i, j, 0))
            elif A[j, i] == 1:
                flip_sequence.append((j, i, 0))

            # Secondary flip (coordinated)
            if attempt % 2 == 0 and flip_sequence:
                k2, l2 = np.random.choice(N, 2, replace=False)
                if (k2, l2) != (i, j) and (l2, k2) != (i, j):
                    if A[k2, l2] == 0 and A[l2, k2] == 0:
                        flip_sequence.append((k2, l2, 1))
                    elif A[k2, l2] == 1:
                        flip_sequence.append((k2, l2, 0))

            # Apply flips
            for idx, jdx, op in flip_sequence:
                if op == 1:
                    A[idx, jdx] = 1
                else:
                    A[idx, jdx] = 0

            # Validate constraints
            valid = all(int(A[i].sum()) >= 8 for i in range(N))

            if valid and is_strongly_connected():
                new_excess = total_excess()
                if new_excess <= best_excess:
                    best_excess = new_excess
                    improved = True
                    plateau_counter = 0
                    iteration += 1
                    if new_excess == 0:
                        return A
                    break

            # Revert flips
            for idx, jdx, op in flip_sequence:
                if op == 1:
                    A[idx, jdx] = 0
                else:
                    A[idx, jdx] = 1

            iteration += 1

        if not improved:
            plateau_counter += 1
        else:
            plateau_counter = 0

    return A
